#include <bits/stdc++.h>
using namespace std;

const int N=200;

struct Edge{
    int u,v;
}ans[N];

bool cmp(Edge x,Edge y){
    if(x.u==y.u)
        return x.v<y.v;
    return x.u<y.u;
}

int n,m,g[N][N],cnt,t[N],low[N],num;

void dfs(int x,int fa){
    t[x]=low[x]=++num;
    for(int i=1;i<=n;i++){
        if(!g[x][i] || i==fa)
            continue;
        if(!t[i]){
            dfs(i,x);
            if(low[i]<t[i])
                low[x]=min(low[x],low[i]);
            else
                ans[++cnt]={min(x,i),max(x,i)};
        }else
            low[x]=min(low[x],t[i]);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        g[u][v]=g[v][u]=1;
    }
    dfs(1,0);
    sort(ans+1,ans+cnt+1,cmp);
    for(int i=1;i<=cnt;i++)
        printf("%d %d\n",ans[i].u,ans[i].v);
    return 0;
}
